import json
from typing import Union


def flatten_ec2_metadata(data: Union[dict, str], max_depth: int = 20) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters:
        data (Union[dict, str]): Either a pre-parsed dict or a raw JSON string representing EC2 metadata.
        max_depth (int): Maximum recursion depth allowed (default: 20).

    Returns:
        dict: A flat dictionary where nested keys are joined with dot-notation and list indices are strings.

    Raises:
        ValueError: If input is None or not a dict/string type.
        ValueError: If a JSON string input cannot be parsed.
        ValueError: If recursion depth exceeds max_depth.

    Example:
        >>> metadata = '{"instanceId": "i-1234", "network": {"interfaces": [{"mac": "0a:1b"}]}}'
        >>> flatten_ec2_metadata(metadata)
        {'instanceId': 'i-1234', 'network.interfaces.0.mac': '0a:1b'}
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError(f"Input must be a dict or JSON string, got {type(data).__name__}")
    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse JSON string: {e}")

    def _flatten(obj, prefix, depth):
        if depth > max_depth:
            raise ValueError(f"Recursion depth exceeded maximum of {max_depth}")
        items = {}
        if isinstance(obj, dict):
            for k, v in obj.items():
                new_key = f"{prefix}.{k}" if prefix else str(k)
                items.update(_flatten(v, new_key, depth + 1))
        elif isinstance(obj, list):
            for i, v in enumerate(obj):
                new_key = f"{prefix}.{i}" if prefix else str(i)
                items.update(_flatten(v, new_key, depth + 1))
        else:
            items[prefix] = obj
        return items

    return _flatten(data, "", 0)

from typing import Any


def filter_dynamodb_items(
    items: list[dict[str, Any]],
    attribute_name: str,
    condition_value: Any,
) -> list[dict[str, Any]]:
    """
    Filter DynamoDB items based on a simple attribute condition.

    Parameters:
        items: List of DynamoDB item dicts in boto3 typed format.
        attribute_name: The attribute name to filter on.
        condition_value: The plain Python value to compare against.

    Returns:
        List of items where the attribute matches the condition value.

    Raises:
        ValueError: If items is None or contains non-dict elements.
    """
    if items is None:
        raise ValueError("items must not be None")
    if not all(isinstance(item, dict) for item in items):
        raise ValueError("All elements in items must be dicts")

    def extract(typed_value: dict[str, Any]) -> Any:
        if "S" in typed_value:
            return typed_value["S"]
        if "N" in typed_value:
            return float(typed_value["N"]) if "." in typed_value["N"] else int(typed_value["N"])
        if "BOOL" in typed_value:
            return typed_value["BOOL"]
        return None

    result = []
    for item in items:
        if attribute_name not in item:
            continue
        if extract(item[attribute_name]) == condition_value:
            result.append(item)
    return result
